import { useEffect, useState } from "react";
import { Link, useNavigate } from "react-router-dom";
import "./Dashboard.css";

function Dashboard() {
  const [questions, setQuestions] = useState([]);
  const navigate = useNavigate();

  const user = JSON.parse(localStorage.getItem("user") || "null");

  // ✅ Protect route
  useEffect(() => {
    if (!user) navigate("/login");
  }, [navigate, user]);

  // ✅ Fetch data
  useEffect(() => {
    fetch("http://localhost:5000/api/questions")
      .then((res) => res.json())
      .then((data) => setQuestions(data))
      .catch((err) => console.error(err));
  }, []);

  const handleLogout = () => {
    localStorage.removeItem("user");
    navigate("/login");
  };

  return (
    <>
      {/* ===== NAVBAR ===== */}
      <div className="nav">
        <div className="nav-left">
          <div className="logo">C</div>
          <div>
            <h3>Campus Connect</h3>
            <p>Student Learning Hub</p>
          </div>
        </div>

        <div className="nav-right">
          <div className="profile">
            <div className="avatar">{user?.name?.[0]}</div>
            <div>
              <p>{user?.name}</p>
              <span>{user?.role}</span>
            </div>
          </div>

          <button onClick={handleLogout}>Logout</button>
        </div>
      </div>

      {/* ===== BODY ===== */}
      <div className="body">

        {/* SIDEBAR */}
        <div className="sidebar">
          <h4>Filters</h4>

          <p className="active">Recent</p>
          <p>Popular</p>

          <h5>Category</h5>
          <p className="active">All Posts</p>
          <p>Study Notes</p>
          <p>Projects</p>
          <p>Guidance</p>
          <p>Career</p>
          <p>Skills</p>
        </div>

        {/* MAIN */}
        <div className="main">

          {/* HEADER */}
          <div className="main-header">
            <div>
              <h2>All Posts</h2>
              <p>{questions.length} posts available</p>
            </div>

            <Link to="/ask" className="new-btn">
              + New Post
            </Link>
          </div>

          {/* POSTS */}
          {questions.map((q) => (
            <div key={q._id} className="card-post">

              <div className="card-top">
                <div className="user">
                  <div className="avatar small">
                    {user?.name?.[0]}
                  </div>

                  <div>
                    <h4>{user?.name}</h4>
                    <p>{user?.role}</p>
                  </div>
                </div>

                <span className="badge">notes</span>
              </div>

              <h3>{q.title}</h3>
              <p className="desc">{q.description}</p>

              <div className="card-bottom">
                <span>❤️ 0</span>
                <span>💬 {q.answer ? 1 : 0}</span>

                <Link to={`/answers/${q._id}`}>
                  View
                </Link>
              </div>

            </div>
          ))}

        </div>
      </div>
    </>
  );
}

export default Dashboard;
